// Dev-mode HTTP host for the @vercel/backends cron dispatcher shim.
//
// Spawned by `startDevServer`. Imports the shim file generated by
// `applyCronDispatch` (the same code that runs in the production lambda
// bundle) and serves its default `(req, res)` handler over a Node
// `http.createServer`. All dispatch logic lives in the shim, not here.
//
// Spawned as `node --import tsx <host.mjs>` so the user's entrypoint
// (which the shim imports) can be .ts/.mts/.cts.
//
// Inputs (env vars):
//   __VC_DISPATCH_SHIM_ABS  absolute path to the generated shim file
//   __VC_PORT               port to bind on
//   CRON_SECRET             optional; honored by the shim itself

import {
  createServer,
  type IncomingMessage,
  type ServerResponse,
} from 'node:http';
import { pathToFileURL } from 'node:url';

const SHIM_ABS = process.env.__VC_DISPATCH_SHIM_ABS;
const PORT = process.env.__VC_PORT;

function bail(message: string): never {
  console.error(`[vercel-backends-cron-host] ${message}`);
  process.exit(1);
}

if (!SHIM_ABS) bail('missing __VC_DISPATCH_SHIM_ABS');
if (!PORT) bail('missing __VC_PORT');

const port = Number.parseInt(PORT, 10);
if (!Number.isFinite(port) || port <= 0) {
  bail(`invalid __VC_PORT: ${PORT}`);
}

type Handler = (
  req: IncomingMessage,
  res: ServerResponse
) => unknown | Promise<unknown>;

async function main() {
  const mod = (await import(pathToFileURL(SHIM_ABS!).href)) as {
    default?: Handler;
  };
  const handler = mod.default;
  if (typeof handler !== 'function') {
    bail(
      `shim at ${SHIM_ABS} did not export a default function (got ${typeof handler})`
    );
  }

  const server = createServer((req, res) => {
    Promise.resolve(handler(req, res)).catch((err: unknown) => {
      console.error(err);
      if (!res.headersSent) {
        res.statusCode = 500;
        res.setHeader('content-type', 'application/json');
        res.end(JSON.stringify({ error: 'internal' }));
      } else {
        try {
          res.end();
        } catch {
          /* response already torn down */
        }
      }
    });
  });

  await new Promise<void>((resolve, reject) => {
    server.once('error', reject);
    server.listen(port, () => {
      server.removeListener('error', reject);
      // Sentinel so test harnesses (and humans) can see when the host
      // is ready. The orchestrator uses port-reachability for readiness,
      // not stdout, so this is informational.
      console.log(`[cron-host] listening on port ${port}`);
      resolve();
    });
  });

  const shutdown = () => {
    server.close(() => process.exit(0));
    setTimeout(() => process.exit(0), 1000).unref();
  };
  process.on('SIGTERM', shutdown);
  process.on('SIGINT', shutdown);
}

main().catch(err => {
  console.error(err);
  process.exit(1);
});
